'use client';

import { useEffect, useState, use } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/lib/supabase';
import { realtimeService } from '@/services/realtimeService';
import { jobService } from '@/services/jobService';
import { ReviewModal } from '@/components/jobs/ReviewModal';
import {
    ChevronLeft, Settings, MessageSquare, Phone, Info,
    Locate as CurrentLocation, Map as MapIcon, Minus, Plus, CheckCircle
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import dynamic from 'next/dynamic';

const LiveTrackingMap = dynamic(() => import('@/components/LiveTrackingMap'), {
    ssr: false,
    loading: () => (
        <div className="h-full w-full bg-[#030208] animate-pulse flex items-center justify-center text-white/30 font-bold tracking-widest uppercase text-xs">
            Initializing Satellites...
        </div>
    )
});

interface TrackingData {
    otp_code: string;
    started_at: string | null;
    current_location: any;
}

export default function JobTracking({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const router = useRouter();
    const { user } = useAuth();

    // -- State --
    const [trackingData, setTrackingData] = useState<TrackingData | null>(null);
    const [simulatedLocation, setSimulatedLocation] = useState<any>(null);
    const [jobStep, setJobStep] = useState(2);
    const [eta, setEta] = useState<string>("8 min");
    const [distance, setDistance] = useState<string>("3.4 km");
    const [isReviewOpen, setIsReviewOpen] = useState(false);

    // -- Effects --
    useEffect(() => {
        if (!id) return;

        // Fetch Data
        const fetchData = async () => {
            // Mock/Real fetch logic
            const data = await jobService.getTrackingDetails(id).catch(() => null);
            if (data) setTrackingData(data);
            setSimulatedLocation({ coordinates: [76.9558, 11.0168] });
        };
        fetchData();

        // Simulator
        const interval = setInterval(() => {
            setSimulatedLocation((prev: any) => {
                if (!prev) return null;
                const newLng = prev.coordinates[0] + (Math.random() - 0.5) * 0.0005;
                const newLat = prev.coordinates[1] + (Math.random() - 0.5) * 0.0005;
                return { coordinates: [newLng, newLat] };
            });
        }, 2000);

        return () => clearInterval(interval);
    }, [id]);

    const handleArrive = () => {
        setJobStep(3); // In Progress
    };

    return (
        <div className="bg-[#030208] min-h-screen relative font-sans overflow-hidden">

            {/* 1. Full Screen Map Layer */}
            <div className="absolute inset-0 z-0">
                {/* We pass a 'dark' prop to map if supported, or handle styles in component */}
                <LiveTrackingMap location={simulatedLocation || trackingData?.current_location} />

                {/* Gradient Map Overlay for depth */}
                <div className="absolute inset-0 bg-gradient-to-b from-[#030208]/80 via-transparent to-[#030208]/80 pointer-events-none mix-blend-multiply z-[1]" />
            </div>

            {/* 2. Top UI Layer */}
            <div className="absolute top-0 left-0 w-full z-20 px-4 pt-10 pb-4">
                {/* Job Lifecycle Indicator */}
                <div className="glass-deep rounded-2xl p-4 mb-4 border border-white/10 shadow-2xl">
                    <div className="flex justify-between items-center mb-3">
                        <span className="text-[10px] font-bold text-white/40 uppercase tracking-widest">Job Lifecycle</span>
                        <span className="text-[10px] font-bold text-[#00f2ff]">On the Way</span>
                    </div>
                    <div className="h-1 bg-white/10 rounded-full flex gap-1 overflow-hidden">
                        {[1, 2, 3, 4].map((step, i) => (
                            <div key={i} className={`h-full flex-1 rounded-full transition-all duration-1000 ${i < jobStep ? 'bg-[#2563eb] shadow-[0_0_10px_rgba(37,99,235,0.6)]' : 'bg-transparent'}`}></div>
                        ))}
                    </div>
                    <div className="flex justify-between mt-2 text-[9px] font-bold text-white/30 uppercase tracking-wider">
                        <span>Accepted</span>
                        <span className="text-white">En Route</span>
                        <span>Working</span>
                        <span>Done</span>
                    </div>
                </div>

                {/* Search / Waypoints */}
                <div className="flex gap-3">
                    <button onClick={() => router.back()} className="h-12 w-12 rounded-2xl glass-premium flex items-center justify-center text-white/70 hover:bg-white/10 transition-all active:scale-95">
                        <ChevronLeft className="w-6 h-6" />
                    </button>
                    <div className="flex-1 h-12 glass-deep rounded-2xl flex items-center px-4 gap-3 border border-white/10">
                        <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(52,211,153,0.8)]"></div>
                        <span className="text-[10px] font-black uppercase text-white tracking-widest">In Progress</span>
                        <input type="text" placeholder="Search for waypoints..." className="bg-transparent border-none outline-none text-xs text-white placeholder:text-white/20 flex-1 h-full" />
                        <button className="text-white/40"><Settings className="w-4 h-4" /></button>
                    </div>
                </div>
            </div>

            {/* 3. Map Controls (Right Side) */}
            <div className="absolute right-4 top-1/2 -translate-y-1/2 z-20 flex flex-col gap-3">
                <button className="w-10 h-10 glass-deep rounded-xl flex items-center justify-center text-white/70 hover:text-white active:scale-90 transition-all border border-white/10">
                    <Plus className="w-5 h-5" />
                </button>
                <button className="w-10 h-10 glass-deep rounded-xl flex items-center justify-center text-white/70 hover:text-white active:scale-90 transition-all border border-white/10">
                    <Minus className="w-5 h-5" />
                </button>
                <button className="w-10 h-10 glass-deep rounded-xl flex items-center justify-center text-[#00f2ff] hover:text-white active:scale-90 transition-all border border-white/10 shadow-[0_0_20px_rgba(0,242,255,0.2)]">
                    <CurrentLocation className="w-5 h-5" />
                </button>
            </div>


            {/* 4. Bottom Card (Live Status) */}
            <div className="absolute bottom-6 left-0 w-full px-4 z-30">
                <motion.div
                    initial={{ y: 200 }}
                    animate={{ y: 0 }}
                    className="glass-deep rounded-[2.5rem] p-6 pb-8 border border-white/10 shadow-[0_-10px_40px_rgba(0,0,0,0.5)] ring-1 ring-white/5 relative overflow-hidden"
                >
                    {/* Driver/Status */}
                    <div className="flex justify-between items-start mb-6">
                        <div>
                            <div className="flex items-center gap-2 mb-1">
                                <MapIcon className="w-3 h-3 text-[#2563eb]" />
                                <span className="text-[10px] font-bold text-[#2563eb] uppercase tracking-widest">Arrival Time</span>
                            </div>
                            <div className="flex items-end gap-3">
                                <h1 className="text-3xl font-black text-white mix-blend-overlay">14:22</h1>
                                <span className="text-sm font-bold text-[#2563eb] mb-1">({eta})</span>
                            </div>
                            <p className="text-xs text-white/40 font-medium">{distance} remaining</p>
                        </div>
                        <div className="flex flex-col items-end">
                            <div className="relative mb-2">
                                <div className="w-12 h-12 rounded-full border-2 border-[#d97706] p-0.5 pointer-events-none">
                                    <img src="https://i.pravatar.cc/150?u=alex" className="w-full h-full rounded-full object-cover" />
                                </div>
                                <div className="absolute -bottom-1 -right-1 bg-[#d97706] text-[8px] font-black text-black px-1.5 py-0.5 rounded-full uppercase">Pro</div>
                            </div>
                            <h3 className="text-sm font-bold text-white text-right">Alexander Pierce</h3>
                            <p className="text-[10px] text-white/30 uppercase tracking-wider">Premium Client</p>
                        </div>
                    </div>

                    {/* Action Grid */}
                    <div className="grid grid-cols-4 gap-3 mb-6">
                        <button onClick={() => router.push(`/messages/${id}`)} className="aspect-square glass-premium rounded-2xl flex items-center justify-center text-white relative active:scale-95 transition-all hover:bg-white/5">
                            <MessageSquare className="w-5 h-5" />
                            <div className="absolute top-2 right-2 w-4 h-4 bg-red-500 rounded-full flex items-center justify-center text-[9px] font-bold border border-[#030208]">2</div>
                        </button>
                        <button className="aspect-square glass-premium rounded-2xl flex items-center justify-center text-red-400 active:scale-95 transition-all hover:bg-red-500/10 border border-red-500/20">
                            <div className="text-xl font-bold">*</div>
                        </button>
                        <button className="aspect-square glass-premium rounded-2xl flex items-center justify-center text-white active:scale-95 transition-all hover:bg-white/5">
                            <Phone className="w-5 h-5" />
                        </button>
                        <button className="aspect-square glass-premium rounded-2xl flex items-center justify-center text-white active:scale-95 transition-all hover:bg-white/5">
                            <Info className="w-5 h-5" />
                        </button>
                    </div>

                    {/* Main Action Button */}
                    <button
                        onClick={handleArrive}
                        className="w-full h-14 bg-[#1e40af] hover:bg-[#1d4ed8] active:scale-[0.98] transition-all rounded-2xl flex items-center justify-center gap-3 shadow-[0_0_30px_rgba(30,64,175,0.4)] border border-white/10 group"
                    >
                        <span className="text-sm font-bold text-white uppercase tracking-widest group-hover:tracking-[0.2em] transition-all">Mark as Arrived</span>
                        <div className="w-5 h-5 bg-white text-[#1e40af] rounded-full flex items-center justify-center">
                            <CheckCircle className="w-3.5 h-3.5" />
                        </div>
                    </button>

                    {/* Handle Bar */}
                    <div className="absolute bottom-2 left-1/2 -translate-x-1/2 w-12 h-1 bg-white/10 rounded-full" />
                </motion.div>
            </div>

        </div>
    );
}
